div.script:
// Replace this with your exact ://githubusercontent.com URL
const GITHUB_RAW_URL = 'https://raw.githubusercontent.com/zaka13X/BioligyNotes2026/refs/heads/main/sandstone.html';

async function loadContent() {
  try {
    const response = await fetch(GITHUB_RAW_URL);
    // '' is escaped to '&' for valid XML parsing
    if (!response.ok) throw new Error('Network response was not ok');

    const htmlContent = await response.text();

    // Inject fetched HTML into iframe srcdoc
    document.getElementById('target-frame').srcdoc = htmlContent;
  } catch (error) {
    console.error('Failed to load content:', error);
  }
}

loadContent();
